import { useState, useEffect } from 'react';
import { FootprintInput, ActionItem } from '../../types';
import { generateReductionPlan } from '../../lib/recommendation-engine';
import { completeAction, uncompleteAction, getLocalHistory } from '../../lib/storage';
import { useToast } from '../ToastProvider';
import { Sparkles, Trophy, Flame } from 'lucide-react';

interface ReductionPlanProps {
  input: FootprintInput;
  onRefreshHistory: () => void;
}

export default function ReductionPlan({ input, onRefreshHistory }: ReductionPlanProps) {
  const { showToast } = useToast();
  const [items, setItems] = useState<ActionItem[]>([]);

  useEffect(() => {
    const generated = generateReductionPlan(input);
    const history = getLocalHistory();

    // Check which items are completed in storage
    const itemsWithCompletion = generated.map((item) => ({
      ...item,
      completed: history.completedActionIds.includes(item.id),
    }));

    setItems(itemsWithCompletion);
  }, [input]);

  const handleToggleCompletion = (id: string) => {
    const history = getLocalHistory();
    const isCompleted = history.completedActionIds.includes(id);

    if (isCompleted) {
      uncompleteAction(id);
      showToast('Action removed from commitments.', 'info');
    } else {
      completeAction(id);
      showToast('Action saved. Small changes compound.', 'success');
    }

    // Update local React state
    setItems((prev) =>
      prev.map((item) => (item.id === id ? { ...item, completed: !item.completed } : item))
    );
    onRefreshHistory(); // trigger parent refresh
  };

  return (
    <div className="bg-white border border-slate-200 rounded-3xl p-6 shadow-sm space-y-6">
      <div>
        <h3 className="text-sm font-bold text-slate-800 uppercase tracking-wider mb-1">
          Your Reduction Plan
        </h3>
        <p className="text-xs text-slate-400">
          A targeted roadmap scaled according to your carbon contributors and daily goals.
        </p>
      </div>

      <div className="space-y-4">
        {items.map((item, index) => {
          const typeTags = [
            {
              label: 'Easiest Action',
              icon: Sparkles,
              color: 'text-emerald-700 bg-emerald-50 border border-emerald-100',
            },
            {
              label: 'Highest Impact',
              icon: Trophy,
              color: 'text-slate-700 bg-slate-50 border border-slate-100',
            },
            {
              label: 'Habit Consistency',
              icon: Flame,
              color: 'text-emerald-700 bg-emerald-50 border border-emerald-100',
            },
          ][index] || {
            label: 'Action Tip',
            icon: Sparkles,
            color: 'text-slate-600 bg-slate-50 border border-slate-100',
          };

          const TagIcon = typeTags.icon;

          return (
            <div
              key={item.id}
              className={`p-5 rounded-2xl border transition-all duration-200 flex flex-col sm:flex-row sm:items-center justify-between gap-4 ${
                item.completed
                  ? 'border-emerald-200 bg-emerald-50/15'
                  : 'border-slate-200 bg-white hover:border-slate-300'
              }`}
            >
              <div className="space-y-3 flex-1">
                {/* Mode Tag label */}
                <div className="flex items-center gap-2">
                  <span
                    className={`inline-flex items-center gap-1.5 px-2.5 py-0.5 rounded-lg text-xs font-bold ${typeTags.color}`}
                  >
                    <TagIcon className="w-3.5 h-3.5" aria-hidden="true" />
                    <span>{typeTags.label}</span>
                  </span>
                  <span className="text-xs font-bold text-slate-450 uppercase tracking-wider bg-slate-100 px-2 py-0.5 rounded-md">
                    Saving ~{item.impactEstimatedKg.toFixed(1)} kg/wk
                  </span>
                </div>
                {/* Description */}
                <p className="text-sm font-semibold text-slate-800 leading-relaxed">{item.text}</p>
              </div>

              {/* Toggle switch Button */}
              <div>
                <button
                  type="button"
                  onClick={() => handleToggleCompletion(item.id)}
                  className={`w-full sm:w-auto px-4 py-2 rounded-xl text-xs font-bold transition-all cursor-pointer ${
                    item.completed
                      ? 'bg-emerald-600 text-white select-none shadow-sm hover:bg-emerald-700'
                      : 'border border-slate-200 text-slate-750 hover:bg-slate-50'
                  }`}
                  aria-pressed={item.completed}
                >
                  {item.completed ? '✓ Committed' : 'Take Action'}
                </button>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

/**
 * CarbonWise - isolated AI helper using the modern @google/genai SDK
 */

import { GoogleGenAI, Type } from '@google/genai';
import type { FootprintInput, CarbonResult, AIResponse } from '../types.js';

// Deterministic engine fallback
export function getDeterministicInsight(input: FootprintInput, result: CarbonResult): AIResponse {
  const driver = result.biggestImpactDriver;

  if (driver === 'transport') {
    return {
      personalInsight: `Your transport choices represent your biggest leverage point, driven by a travel total of ${input.distancePerDayKm || 0} km/day.`,
      motivationalNudge: `Every active carbon-free trip you take helps avoid harmful greenhouse emissions. Small actions build sustainable compound savings!`,
      customAction: `Try carpooling or taking bus/metro transit for your primary commute on 2 days this week.`,
    };
  } else if (driver === 'energy') {
    return {
      personalInsight: `Home energy utility usage (${input.electricityKwhMonthly || 0} kWh) partitioned per capita represents your biggest footprint component.`,
      motivationalNudge: `Trimming standby draws and keeping cooling efficiency high protects both our climate and household finances.`,
      customAction: `Reduce home AC use by one hour and wash your next batch of laundry in cold water.`,
    };
  } else if (driver === 'consumption') {
    return {
      personalInsight: `Manufacturing and shipping your monthly deliveries and clothing represents a heavy pre-consumer carbon footprint.`,
      motivationalNudge: `Repairing and consolidating orders directly avoids energy-intensive manufacturing cycles. Repair first, purchase second!`,
      customAction: `Postpone buying any non-urgent retail apparel and combine your next online orders into one batch delivery limit.`,
    };
  } else {
    // food fallback
    return {
      personalInsight: `Your nutrition style (${input.dietType}) and eating cadence are your principal footprint contributors.`,
      motivationalNudge: `Plant-forward recipes use a fraction of the land, water, and resources of conventional ingredients. Good cooking, good impact.`,
      customAction: `Swap meat for a completely vegetable-forward dinner on three days this week.`,
    };
  }
}

/**
 * Filter any overclaiming or certified words to maintain educational correctness
 */
function sanitizeAiResponse(response: AIResponse): AIResponse {
  const sanitizeText = (txt: string) => {
    return txt
      .replace(/\bexact emissions\b/gi, 'educational estimates')
      .replace(/\bexact carbon footprint\b/gi, 'approximate carbon footprint')
      .replace(/\bcertified\b/gi, 'estimated')
      .replace(/\bofficial accounting\b/gi, 'educational estimates')
      .replace(/\bguaranteed emissions\b/gi, 'approximate emissions');
  };

  return {
    personalInsight: sanitizeText(response.personalInsight).slice(0, 300),
    motivationalNudge: sanitizeText(response.motivationalNudge).slice(0, 300),
    customAction: sanitizeText(response.customAction).slice(0, 150),
  };
}

/**
 * Executes a Gemini 3.5 Flash chat call safely, validating the response schema
 * and failing back gracefully on any error/timeout.
 */
export async function getAiInsight(
  input: FootprintInput,
  result: CarbonResult,
  apiKey?: string
): Promise<{ source: string } & AIResponse> {
  if (!apiKey || apiKey === 'MY_GEMINI_API_KEY' || apiKey.trim() === '') {
    return {
      source: 'deterministic',
      ...getDeterministicInsight(input, result),
    };
  }

  try {
    const ai = new GoogleGenAI({ apiKey });

    const prompt = `You are a carbon footprint expert. Analyze this individual's lifestyle:
- Commute: ${input.commuteMode} for ${input.distancePerDayKm} km/day (Carpool: ${input.carpool ? 'Yes' : 'No'})
- Air Travel: ${input.flightsThisMonth} flights this month
- Home Energy: Electricity use ${input.electricityKwhMonthly} kWh/month, AC level is ${input.acUsage}, and household size is ${input.householdSize}
- Food Diet: ${input.dietType}, waste: ${input.foodWaste}, eat out: ${input.eatingOutFrequency}
- Consumption: ${input.onlineOrdersMonthly} online packages and ${input.clothingPurchasesMonthly} apparel buys per month, recycling habit is ${input.recyclingHabit}
- Reduction Target Goal: ${input.reductionTarget}%, Preferred Effort: ${input.preferredEffort}. Extra Notes: ${input.optionalNote || 'None'}

Provide educational carbon footprint feedback. Do NOT express guilt or shaming, no political rants, no fake precision, no unsupported claims, use short practical language.
Return a JSON object conforming exactly to this schema:
{
  "personalInsight": string (A tailored, compact advice highlighting their top footprint driver and why it matters under 300 chars),
  "motivationalNudge": string (A supportive, highly positive sentence matching their preferred level of effort: ${input.preferredEffort}, under 300 chars),
  "customAction": string (A highly direct activity they can do this week, e.g. 'Commute on rail twice', under 150 chars)
}
`;

    const response = await ai.models.generateContent({
      model: 'gemini-2.0-flash',
      contents: prompt,
      config: {
        responseMimeType: 'application/json',
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            personalInsight: {
              type: Type.STRING,
              description: 'Educational estimate context. No overclaiming words allowed.',
            },
            motivationalNudge: {
              type: Type.STRING,
              description: 'Friendly, encouraging nudge matching user effort commitment level.',
            },
            customAction: {
              type: Type.STRING,
              description: 'Actionable weekly habit swap tip.',
            },
          },
          required: ['personalInsight', 'motivationalNudge', 'customAction'],
        },
      },
    });

    const parsedContent = JSON.parse(response.text || '{}');
    if (
      parsedContent.personalInsight &&
      parsedContent.motivationalNudge &&
      parsedContent.customAction
    ) {
      const sanitized = sanitizeAiResponse({
        personalInsight: String(parsedContent.personalInsight),
        motivationalNudge: String(parsedContent.motivationalNudge),
        customAction: String(parsedContent.customAction),
      });
      return {
        source: 'gemini',
        ...sanitized,
      };
    }

    throw new Error('AI response is missing standard JSON properties.');
  } catch (error) {
    // Graceful fallback
    return {
      source: 'deterministic_fallback',
      ...getDeterministicInsight(input, result),
    };
  }
}

/**
 * CarbonWise - Deterministic Carbon Engine
 */

import type {
  FootprintInput,
  CarbonResult,
  CategoryBreakdown,
  CategoryPercentages,
} from '../types.js';
import {
  EMISSION_FACTORS_TRANSPORT,
  EMISSION_FACTOR_FLIGHT,
  EMISSION_FACTOR_ELECTRICITY,
  AC_DAILY_KWH,
  EMISSION_FACTORS_DIET,
  EMISSION_FACTORS_FOOD_WASTE,
  EMISSION_FACTORS_EATING_OUT,
  EMISSION_FACTOR_ONLINE_ORDER,
  EMISSION_FACTOR_CLOTHING,
  EMISSION_FACTORS_RECYCLING,
  FOOTPRINT_BANDS,
} from './constants.js';
import { clampValue } from './sanitize.js';

/**
 * Calculates daily Transport emissions in kg CO2e
 */
export function calculateDailyTransport(
  commuteMode: FootprintInput['commuteMode'],
  distanceKm: number,
  carpool: boolean,
  flightsMonthly: number = 0
): number {
  const modeFactor = EMISSION_FACTORS_TRANSPORT[commuteMode] ?? 0;
  const multiplier = commuteMode === 'Car' && carpool ? 0.5 : 1.0;

  const dailyCommuteEmission = distanceKm * modeFactor * multiplier;
  const dailyFlightEmission = (flightsMonthly * EMISSION_FACTOR_FLIGHT) / 30.0;

  return clampValue(dailyCommuteEmission + dailyFlightEmission, 0, 1000);
}

/**
 * Calculates daily, per-capita Home Energy emissions in kg CO2e
 */
export function calculateDailyEnergy(
  electricityKwh: number,
  acUsage: FootprintInput['acUsage'],
  householdSize: number
): number {
  const normHouseholdSize = clampValue(householdSize, 1, 20);

  const monthlyElectricityEmissions = electricityKwh * EMISSION_FACTOR_ELECTRICITY;
  const dailyElectricityEmissions = monthlyElectricityEmissions / 30.0;

  // AC emissions
  const dailyAcKwh = AC_DAILY_KWH[acUsage] ?? 0;
  const dailyAcEmissions = dailyAcKwh * EMISSION_FACTOR_ELECTRICITY;

  // Split energy emissions across household size
  const totalDailyEnergy = (dailyElectricityEmissions + dailyAcEmissions) / normHouseholdSize;

  return clampValue(totalDailyEnergy, 0, 1000);
}

/**
 * Calculates daily Food emissions in kg CO2e
 */
export function calculateDailyFood(
  dietType: FootprintInput['dietType'],
  foodWaste: FootprintInput['foodWaste'],
  eatingOut: FootprintInput['eatingOutFrequency']
): number {
  const dietBase = EMISSION_FACTORS_DIET[dietType] ?? 2.0;
  const wasteBase = EMISSION_FACTORS_FOOD_WASTE[foodWaste] ?? 0.0;
  const eatingOutBase = EMISSION_FACTORS_EATING_OUT[eatingOut] ?? 0.0;

  return clampValue(dietBase + wasteBase + eatingOutBase, 0, 100);
}

/**
 * Calculates daily Consumption emissions in kg CO2e
 */
export function calculateDailyConsumption(
  onlineOrders: number,
  clothingPurchases: number,
  recyclingHabit: FootprintInput['recyclingHabit']
): number {
  const ordersMonthlyEmissions = onlineOrders * EMISSION_FACTOR_ONLINE_ORDER;
  const clothingMonthlyEmissions = clothingPurchases * EMISSION_FACTOR_CLOTHING;

  const dailyPurchaseEmissions = (ordersMonthlyEmissions + clothingMonthlyEmissions) / 30.0;
  const recyclingAdj = EMISSION_FACTORS_RECYCLING[recyclingHabit] ?? 0.2;

  // Total can be offset by positive recycling but shouldn't drop below 0
  return clampValue(dailyPurchaseEmissions + recyclingAdj, 0, 200);
}

/**
 * Process a check-in input, generating the comprehensive carbon analysis result.
 */
export function calculateFootprint(input: FootprintInput): CarbonResult {
  const transport = calculateDailyTransport(
    input.commuteMode,
    input.distancePerDayKm,
    input.carpool,
    input.flightsThisMonth
  );

  const energy = calculateDailyEnergy(
    input.electricityKwhMonthly,
    input.acUsage,
    input.householdSize
  );

  const food = calculateDailyFood(input.dietType, input.foodWaste, input.eatingOutFrequency);

  const consumption = calculateDailyConsumption(
    input.onlineOrdersMonthly,
    input.clothingPurchasesMonthly,
    input.recyclingHabit
  );

  const dailyTotal = transport + energy + food + consumption;
  const weeklyTotal = dailyTotal * 7.0;
  const monthlyTotal = dailyTotal * 30.0;

  // Percentages mapping
  const breakdown: CategoryBreakdown = { transport, energy, food, consumption };
  const percentages: CategoryPercentages = {
    transport: dailyTotal > 0 ? (transport / dailyTotal) * 100 : 0,
    energy: dailyTotal > 0 ? (energy / dailyTotal) * 100 : 0,
    food: dailyTotal > 0 ? (food / dailyTotal) * 100 : 0,
    consumption: dailyTotal > 0 ? (consumption / dailyTotal) * 100 : 0,
  };

  // Determine footprintband
  let footprintBand: CarbonResult['footprintBand'] = 'Moderate';
  if (dailyTotal < FOOTPRINT_BANDS.Light.max) {
    footprintBand = 'Light';
  } else if (dailyTotal < FOOTPRINT_BANDS.Moderate.max) {
    footprintBand = 'Moderate';
  } else if (dailyTotal < FOOTPRINT_BANDS.High.max) {
    footprintBand = 'High';
  } else {
    footprintBand = 'Very High';
  }

  // Determine biggest driver
  let biggestImpactDriver: CarbonResult['biggestImpactDriver'] = 'food';
  let maxVal = food;

  if (transport > maxVal) {
    maxVal = transport;
    biggestImpactDriver = 'transport';
  }
  if (energy > maxVal) {
    maxVal = energy;
    biggestImpactDriver = 'energy';
  }
  if (consumption > maxVal) {
    maxVal = consumption;
    biggestImpactDriver = 'consumption';
  }

  return {
    dailyTotal,
    weeklyTotal,
    monthlyTotal,
    footprintBand,
    breakdown,
    percentages,
    biggestImpactDriver,
    input: { ...input },
  };
}

/**
 * CarbonWise - Safe Client-Side LocalStorage Persistence
 */

import type { CheckInRecord, FootprintInput, CarbonResult, LocalHistory } from '../types.js';

const STORAGE_KEY = 'carbonwise_state_v1';

const DEFAULT_STATE: LocalHistory = {
  checkIns: [],
  completedActionIds: [],
  customActions: [],
};

/**
 * Checks if localStorage is available and accessible
 */
function getSafeLocalStorage(): Storage | null {
  if (typeof window === 'undefined') return null;
  try {
    // Some sandboxed frames throw on accessing the property itself
    const storage = window.localStorage;
    if (!storage) return null;
    return storage;
  } catch {
    return null;
  }
}

// In-Memory fallback for server environments or testing
let memoryState: LocalHistory = { ...DEFAULT_STATE };

/**
 * Loads the user profile history and actions state
 */
export function getLocalHistory(): LocalHistory {
  const storage = getSafeLocalStorage();
  if (!storage) {
    return memoryState;
  }

  try {
    const raw = storage.getItem(STORAGE_KEY);
    if (!raw) {
      return { ...DEFAULT_STATE, checkIns: [], completedActionIds: [], customActions: [] };
    }
    const parsed = JSON.parse(raw);

    // Integrity checks for corrupt data
    if (!parsed || typeof parsed !== 'object') {
      return { ...DEFAULT_STATE, checkIns: [], completedActionIds: [], customActions: [] };
    }

    return {
      checkIns: Array.isArray(parsed.checkIns) ? parsed.checkIns : [],
      completedActionIds: Array.isArray(parsed.completedActionIds) ? parsed.completedActionIds : [],
      customActions: Array.isArray(parsed.customActions) ? parsed.customActions : [],
    };
  } catch (err) {
    // Graceful recovery from corrupt storage formats
    return { ...DEFAULT_STATE, checkIns: [], completedActionIds: [], customActions: [] };
  }
}

/**
 * Saves the history state back to local storage
 */
export function saveLocalHistory(state: LocalHistory): void {
  const storage = getSafeLocalStorage();
  if (!storage) {
    memoryState = { ...state };
    return;
  }
  try {
    storage.setItem(STORAGE_KEY, JSON.stringify(state));
  } catch (err) {
    // Fail-safe
  }
}

/**
 * Adds a new check-in to the user's history log
 */
export function addCheckIn(input: FootprintInput, result: CarbonResult): CheckInRecord {
  const history = getLocalHistory();

  const newRecord: CheckInRecord = {
    id: `chk_${Date.now()}_${Math.random().toString(36).slice(2, 6)}`,
    timestamp: new Date().toISOString(),
    input: JSON.parse(JSON.stringify(input)),
    result: JSON.parse(JSON.stringify(result)),
  };

  history.checkIns.unshift(newRecord); // Prepend so most recent is first
  saveLocalHistory(history);
  return newRecord;
}

/**
 * Records completion of an action
 */
export function completeAction(actionId: string): void {
  const history = getLocalHistory();
  if (!history.completedActionIds.includes(actionId)) {
    history.completedActionIds.push(actionId);
    saveLocalHistory(history);
  }
}

/**
 * Removes a completed action mark
 */
export function uncompleteAction(actionId: string): void {
  const history = getLocalHistory();
  history.completedActionIds = history.completedActionIds.filter((id) => id !== actionId);
  saveLocalHistory(history);
}

/**
 * Resets all dashboard data
 */
export function clearStorageData(): void {
  try {
    const storage = getSafeLocalStorage();
    if (storage) {
      storage.removeItem(STORAGE_KEY);
    }
  } catch (err) {
    // Fail-safe
  }
  memoryState = {
    checkIns: [],
    completedActionIds: [],
    customActions: [],
  };
}

/**
 * Calculates current action streak based on total completed action counts
 * or sequential daily check-ins
 */
export function getReductionStreak(): number {
  const history = getLocalHistory();

  // Return the count of successfully saved green action completions
  return history.completedActionIds.length;
}

/**
 * Analyzes check-in history to determine if a category has shown the most improvement
 */
export function getBestCategoryImproved(): string {
  const history = getLocalHistory();
  if (history.checkIns.length < 2) return 'None (Keep checking in)';

  // Compare oldest vs newest check-in to find the category with the largest drop in emissions
  const newest = history.checkIns[0].result.breakdown;
  const oldest = history.checkIns[history.checkIns.length - 1].result.breakdown;

  const differences = {
    transport: oldest.transport - newest.transport,
    energy: oldest.energy - newest.energy,
    food: oldest.food - newest.food,
    consumption: oldest.consumption - newest.consumption,
  };

  let bestCat = 'None';
  let maxReduction = 0;

  for (const [cat, val] of Object.entries(differences)) {
    if (val > maxReduction) {
      maxReduction = val;
      bestCat = cat;
    }
  }

  if (bestCat === 'None' || maxReduction <= 0.05) {
    return 'Stable (Steady Progress)';
  }

  // Format to standard category names
  return bestCat.charAt(0).toUpperCase() + bestCat.slice(1);
}

/**
 * CarbonWise - Safe Client Storage Engine Tests (Vitest)
 */

import { describe, it, expect, beforeEach } from 'vitest';
import {
  getLocalHistory,
  saveLocalHistory,
  addCheckIn,
  completeAction,
  clearStorageData,
  getReductionStreak,
  getBestCategoryImproved,
} from '../lib/storage';
import { FootprintInput, CarbonResult } from '../types';

describe('Local Profile Storage and Retention', () => {
  beforeEach(() => {
    clearStorageData();
  });

  it('starts with an empty state on fresh initialization', () => {
    const history = getLocalHistory();
    expect(history.checkIns.length).toBe(0);
    expect(history.completedActionIds.length).toBe(0);
  });

  it('allows saving high-integrity footprint checks', () => {
    const mockInput: FootprintInput = {
      commuteMode: 'Walk',
      distancePerDayKm: 0,
      carpool: false,
      electricityKwhMonthly: 0,
      acUsage: 'None',
      householdSize: 1,
      dietType: 'Plant-forward',
      foodWaste: 'Rare',
      eatingOutFrequency: 'Rare',
      onlineOrdersMonthly: 0,
      clothingPurchasesMonthly: 0,
      recyclingHabit: 'Often',
      reductionTarget: 5,
      preferredEffort: 'Easy',
    };

    const mockResult: CarbonResult = {
      dailyTotal: 1.0,
      weeklyTotal: 7.0,
      monthlyTotal: 30.0,
      footprintBand: 'Light',
      breakdown: { transport: 0, energy: 0, food: 1.0, consumption: 0 },
      percentages: { transport: 0, energy: 0, food: 100, consumption: 0 },
      biggestImpactDriver: 'food',
      input: mockInput,
    };

    const record = addCheckIn(mockInput, mockResult);
    expect(record.id).toBeDefined();

    const history = getLocalHistory();
    expect(history.checkIns.length).toBe(1);
    expect(history.checkIns[0].result.dailyTotal).toBe(1.0);
  });

  it('handles completed green next step flags', () => {
    completeAction('step-food-plant-dinner');
    const history = getLocalHistory();
    expect(history.completedActionIds).toContain('step-food-plant-dinner');
    expect(getReductionStreak()).toBe(1);
  });

  it('recovers from empty or malformed localStorage payloads', () => {
    localStorage.setItem('carbonwise_v1', '{malformed: "json"');

    // getLocalHistory should catch the parse error and return default
    const history = getLocalHistory();
    expect(history.checkIns).toEqual([]);
    expect(history.completedActionIds).toEqual([]);
    expect(history.customActions).toEqual([]);
  });
});
